import { Link, useLocation } from "react-router-dom";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap');

  :root {
    --nav-height: 64px;
    --bg: #f5f0e8;
    --surface: #faf7f2;
    --border: #e2d9cc;
    --ink: #1a1612;
    --ink-muted: #7a6f63;
    --accent: #c8441a;
    --accent-hover: #a83515;
    --transition: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  }

  /* ── Navbar ── */
  .navbar {
    width: 100%;
    height: var(--nav-height);
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    background: rgba(26, 22, 18, 0.92);
    backdrop-filter: blur(18px) saturate(1.6);
    -webkit-backdrop-filter: blur(18px) saturate(1.6);
    display: flex;
    align-items: center;
    padding: 0 32px;
    font-family: 'DM Sans', sans-serif;
    z-index: 100;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    box-shadow: 0 1px 24px rgba(0,0,0,0.25);
  }

  /* ── Brand ── */
  .navbar-brand {
    display: flex;
    align-items: center;
    gap: 2px;
    text-decoration: none;
    flex-shrink: 0;
    margin-right: 48px;
  }

  .navbar-brand h2 {
    font-family: 'Playfair Display', serif;
    font-size: 1.35rem;
    font-weight: 700;
    color: #fff;
    letter-spacing: -0.02em;
    line-height: 1;
    margin: 0;
  }

  .navbar-brand .brand-dot {
    display: inline-block;
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: var(--accent);
    margin-left: 2px;
    margin-bottom: 2px;
    vertical-align: middle;
  }

  /* ── Nav Links ── */
  .navbar-nav {
    display: flex;
    align-items: center;
    gap: 4px;
    flex: 1;
  }

  .navbar-link {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-radius: 8px;
    text-decoration: none;
    color: rgba(255,255,255,0.5);
    font-size: 0.85rem;
    font-weight: 400;
    letter-spacing: 0.01em;
    transition: color var(--transition), background var(--transition), transform var(--transition);
    position: relative;
    white-space: nowrap;
  }

  .navbar-link:hover {
    color: rgba(255,255,255,0.92);
    background: rgba(255,255,255,0.07);
    transform: translateY(-1px);
  }

  .navbar-link.active {
    color: #fff;
    background: rgba(200,68,26,0.16);
  }

  .navbar-link.active .nav-icon {
    color: var(--accent);
  }

  /* Active bottom bar indicator */
  .navbar-link.active::after {
    content: '';
    position: absolute;
    bottom: -1px;
    left: 20%;
    right: 20%;
    height: 2.5px;
    border-radius: 2px 2px 0 0;
    background: var(--accent);
    animation: slideIn 200ms ease-out;
  }

  @keyframes slideIn {
    from { transform: scaleX(0); opacity: 0; }
    to   { transform: scaleX(1); opacity: 1; }
  }

  .nav-icon {
    width: 16px;
    height: 16px;
    flex-shrink: 0;
    opacity: 0.75;
    transition: color var(--transition), opacity var(--transition);
  }

  .navbar-link:hover .nav-icon { opacity: 1; }

  /* ── Footer / Right section ── */
  .navbar-right {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-left: auto;
    flex-shrink: 0;
  }

  .navbar-right p {
    font-size: 0.65rem;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    color: rgba(255,255,255,0.22);
    margin: 0;
  }

  /* ── Responsive ── */
  @media (max-width: 768px) {
    .navbar {
      padding: 0 16px;
    }
    .navbar-brand {
      margin-right: 20px;
    }
    .navbar-link {
      padding: 8px 10px;
      font-size: 0;        /* hide text on small screens */
      gap: 0;
    }
    .navbar-link .nav-icon {
      width: 18px;
      height: 18px;
    }
  }
`;

const navItems = [
  {
    to: "/home",
    label: "Dashboard",
    icon: (
      <svg className="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <rect x="3" y="3" width="7" height="7" /><rect x="14" y="3" width="7" height="7" />
        <rect x="3" y="14" width="7" height="7" /><rect x="14" y="14" width="7" height="7" />
      </svg>
    ),
  },
  {
    to: "/profile",
    label: "Profile",
    icon: (
      <svg className="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
        <circle cx="12" cy="7" r="4" />
      </svg>
    ),
  },
  {
    to: "/messages",
    label: "Messages",
    icon: (
      <svg className="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
      </svg>
    ),
  },
  {
    to: "/following",
    label: "Following",
    icon: (
      <svg className="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
      </svg>
    ),
  },
  {
    to: "/followers",
    label: "Followers",
    icon: (
      <svg className="nav-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
        <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
        <circle cx="9" cy="7" r="4" />
        <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
        <path d="M16 3.13a4 4 0 0 1 0 7.75" />
      </svg>
    ),
  },
];

export default function Sidebar() {
  const location = useLocation();

  return (
    <>
      <style>{styles}</style>
      <nav className="navbar">
        {/* Brand */}
        <div className="navbar-brand">
          <h2>Connect<span className="brand-dot" /></h2>
        </div>

        {/* Nav Links */}
        <div className="navbar-nav">
          {navItems.map(({ to, label, icon }) => (
            <Link
              key={to}
              to={to}
              className={`navbar-link${location.pathname === to ? " active" : ""}`}
            >
              {icon}
              {label}
            </Link>
          ))}
        </div>


      </nav>
    </>
  );
}
